it("should return premium 45 G for a single plain potion — 40 G base + 5 G fee", () => {
  const input = {
    customer: { yearsWithMHPCO: 0 },
    steps: [
      {
        op: "quote" as const,
        items: [
          { type: "potion", material: "glass", enchantment: 0, cursed: false },
        ],
      },
    ],
  };
  const result = claimOffice(input);
  expect(result).toEqual({ results: [{ premium: 45 }] });
});

